#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int a[n], b[m];
        for (int i = 0; i < n; i++) scanf("%d", &a[i]);
        for (int i = 0; i < m; i++) scanf("%d", &b[i]);
        qsort(a, n, sizeof(int), compare);
        qsort(b, m, sizeof(int), compare);
        int i = 0, j = 0, count = 0;
        while (i < n && j < m) {
            if (a[i] <= b[j]) {
                i++;
                j++;
                count++;
            } else {
                j++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

